/**
 * Curated list of signatures that identify AI agents / coding bots in commit
 * messages and `Co-Authored-By:` trailers.
 *
 * This list is maintained with the action and expanded in new releases as new
 * tools appear. Users do NOT edit this file to add their own terms — instead
 * they pass the `extra-ai-keywords` input, which is merged on top of these
 * signatures at run time.
 *
 * Entries are full regular expressions (case-insensitive) so they can be as
 * precise as needed. Each pattern carries its own boundaries; keep them tight
 * to avoid false positives on ordinary prose.
 *
 * Last reviewed: 2026-06-28
 */
const AI_SIGNATURES = [
  // Anthropic
  /\bclaude\b/i,
  /@anthropic\.com\b/i,

  // OpenAI
  /\bchatgpt\b/i,
  /\bgpt-?\d*\b/i, // gpt, gpt4, gpt-4, gpt-4o, ...
  /\bopenai\b/i,
  /\bcodex\b/i,
  /@openai\.com\b/i,

  // GitHub / Microsoft
  /\bcopilot\b/i,

  // Google
  /\bgemini\b/i,
  /\bjules\b/i, // Google Jules coding agent

  // Amazon
  /\bamazon q\b/i,
  /\bcodewhisperer\b/i,

  // Standalone agents / IDEs / assistants
  /\bcursor\b/i,
  /\bdevin\b/i,
  /\baider\b/i,
  /\bcodeium\b/i,
  /\bwindsurf\b/i,
  /\btabnine\b/i,
  /\bsourcegraph cody\b/i,

  // GitHub App bot accounts, e.g. "dependabot[bot]", "github-actions[bot]"
  /\[bot\]/i,

  // Generic terms kept for backward compatibility (broader, may catch prose)
  /\bAI\b/i,
  /\bagent\b/i,
];

module.exports = { AI_SIGNATURES };
